<script setup lang="ts">
import{onMounted,ref}from'vue';import{api}from'../api/client';import{useAsyncTask}from'../composables/useAsyncTask';import CapabilityCard from'../components/CapabilityCard.vue';import type{CapabilityResponse}from'../types/capabilities'
const data=ref<CapabilityResponse|null>(null),{loading,error,run}=useAsyncTask();onMounted(()=>run(async()=>{data.value=(await api.get<CapabilityResponse>('/agent-capabilities')).data}))
</script>
<template><div class="page"><div class="page-title"><div><h1>Agent 能力中心</h1><p>检查系统实际启用的 Skill、版本化 Prompt、白名单 Tool 与 MCP 网关。</p></div></div><p v-if="error" class="notice error">{{error}}</p><div v-if="loading" class="empty">正在读取能力注册中心…</div><template v-else-if="data"><section class="card"><div class="section-header"><div><h2>MCP 安全网关</h2><p class="muted">{{data.mcp.transport}}；远端调用默认 {{data.mcp.remote_default}}</p></div><span class="status ready">{{data.mcp.enabled?'已启用':'未启用'}}</span></div><div class="capability-tags"><span v-for="method in data.mcp.methods" :key="method">{{method}}</span></div></section><section><h2>Skills（{{data.skills.length}}）</h2><div class="capability-grid"><CapabilityCard v-for="item in data.skills" :key="item.name+item.version" v-bind="item" :tags="item.allowed_tools"><p class="muted">Prompt：{{item.prompt}}</p></CapabilityCard></div></section><section><h2>Prompts（{{data.prompts.length}}）</h2><div class="capability-grid"><CapabilityCard v-for="item in data.prompts" :key="item.name+item.version" v-bind="item" :tags="[item.output_mode,...item.variables]"/></div></section><section><h2>Tools（{{data.tools.length}}）</h2><div class="capability-grid"><CapabilityCard v-for="item in data.tools" :key="item.name" v-bind="item" :tags="[item.read_only?'只读':'可写']"/></div></section></template></div></template>
